<?php/** * Functions which enhance the theme by hooking into WordPress * * @package AquaLuxe *//** * Get the layout for the current page. * * @return string The layout. */function aqualuxe_get_layout() {	// Check if we have a custom layout for the current page.	if ( is_singular() ) {		$layout = get_post_meta( get_the_ID(), 'aqualuxe_page_layout', true );		if ( $layout ) {			return $layout;		}	}	// Get the default layout from the theme options.	$layout = get_theme_mod( 'aqualuxe_layout', 'right-sidebar' );	// Override layout for specific templates.	if ( is_front_page() ) {		$layout = get_theme_mod( 'aqualuxe_front_page_layout', 'full-width' );	} elseif ( is_home() ) {		$layout = get_theme_mod( 'aqualuxe_blog_layout', 'right-sidebar' );	} elseif ( is_archive() ) {		$layout = get_theme_mod( 'aqualuxe_archive_layout', 'right-sidebar' );	} elseif ( is_search() ) {		$layout = get_theme_mod( 'aqualuxe_search_layout', 'right-sidebar' );	} elseif ( is_404() ) {		$layout = 'full-width';	}	// Override layout for WooCommerce templates.	if ( function_exists( 'is_woocommerce' ) && is_woocommerce() ) {		if ( is_shop() ) {			$layout = get_theme_mod( 'aqualuxe_shop_layout', 'left-sidebar' );		} elseif ( is_product() ) {			$layout = get_theme_mod( 'aqualuxe_product_layout', 'full-width' );		} elseif ( is_product_category() || is_product_tag() ) {			$layout = get_theme_mod( 'aqualuxe_product_archive_layout', 'left-sidebar' );		}	}	return $layout;}/** * Check if the current page has a sidebar. * * @return bool Whether the current page has a sidebar. */function aqualuxe_has_sidebar() {	$layout = aqualuxe_get_layout();	return 'full-width' !== $layout && 'no-sidebar' !== $layout;}/** * Adds custom classes to the array of body classes. * * @param array $classes Classes for the body element. * @return array */function aqualuxe_body_classes( $classes ) {	// Adds a class of hfeed to non-singular pages.	if ( ! is_singular() ) {		$classes[] = 'hfeed';	}	// Adds a class if no sidebar is present.	if ( ! aqualuxe_has_sidebar() ) {		$classes[] = 'no-sidebar';	}	// Add a class for the layout.	$layout = aqualuxe_get_layout();	$classes[] = 'layout-' . $layout;	// Add a class for the header style.	$header_style = get_theme_mod( 'aqualuxe_header_style', 'default' );	$classes[] = 'header-style-' . $header_style;	// Add a class for the footer style.	$footer_style = get_theme_mod( 'aqualuxe_footer_style', 'default' );	$classes[] = 'footer-style-' . $footer_style;	// Add a class for the color scheme.	$color_scheme = get_theme_mod( 'aqualuxe_color_scheme', 'default' );	$classes[] = 'color-scheme-' . $color_scheme;	return $classes;}add_filter( 'body_class', 'aqualuxe_body_classes' );/** * Add a pingback url auto-discovery header for single posts, pages, or attachments. */function aqualuxe_pingback_header() {	if ( is_singular() && pings_open() ) {		printf( '<link rel="pingback" href="%s">', esc_url( get_bloginfo( 'pingback_url' ) ) );	}}add_action( 'wp_head', 'aqualuxe_pingback_header' );/** * Display the breadcrumbs. */function aqualuxe_breadcrumbs() {	// Check if breadcrumbs are enabled.	$show_breadcrumbs = get_theme_mod( 'aqualuxe_show_breadcrumbs', true );	if ( ! $show_breadcrumbs ) {		return;	}	// Check if we're on the front page.	if ( is_front_page() ) {		return;	}	// Get the breadcrumbs separator.	$separator = get_theme_mod( 'aqualuxe_breadcrumbs_separator', '/' );	// Start the breadcrumbs.	echo '<div class="breadcrumbs py-4 text-sm text-gray-600 dark:text-gray-400">';	echo '<div class="container mx-auto px-4">';	echo '<span class="breadcrumb-item"><a href="' . esc_url( home_url( '/' ) ) . '">' . esc_html__( 'Home', 'aqualuxe' ) . '</a></span>';	echo '<span class="breadcrumb-separator mx-2">' . esc_html( $separator ) . '</span>';	if ( is_home() ) {		// Blog page.		echo '<span class="breadcrumb-item current">' . esc_html__( 'Blog', 'aqualuxe' ) . '</span>';	} elseif ( is_category() ) {		// Category archive.		$category = get_queried_object();		echo '<span class="breadcrumb-item current">' . esc_html( $category->name ) . '</span>';	} elseif ( is_tag() ) {		// Tag archive.		$tag = get_queried_object();		echo '<span class="breadcrumb-item current">' . esc_html( $tag->name ) . '</span>';	} elseif ( is_author() ) {		// Author archive.		$author = get_queried_object();		echo '<span class="breadcrumb-item current">' . esc_html( $author->display_name ) . '</span>';	} elseif ( is_year() ) {		// Year archive.		echo '<span class="breadcrumb-item current">' . esc_html( get_the_date( 'Y' ) ) . '</span>';	} elseif ( is_month() ) {		// Month archive.		echo '<span class="breadcrumb-item current">' . esc_html( get_the_date( 'F Y' ) ) . '</span>';	} elseif ( is_day() ) {		// Day archive.		echo '<span class="breadcrumb-item current">' . esc_html( get_the_date() ) . '</span>';	} elseif ( is_tax() ) {		// Custom taxonomy archive.		$term = get_queried_object();		echo '<span class="breadcrumb-item current">' . esc_html( $term->name ) . '</span>';	} elseif ( is_post_type_archive() ) {		// Custom post type archive.		$post_type = get_post_type_object( get_post_type() );		echo '<span class="breadcrumb-item current">' . esc_html( $post_type->labels->name ) . '</span>';	} elseif ( is_singular() ) {		// Single post, page, or custom post type.		$post_type = get_post_type_object( get_post_type() );		if ( 'post' === get_post_type() ) {			// If it's a post, show the categories.			$categories = get_the_category();			if ( ! empty( $categories ) ) {				$category = $categories[0];				echo '<span class="breadcrumb-item"><a href="' . esc_url( get_category_link( $category->term_id ) ) . '">' . esc_html( $category->name ) . '</a></span>';				echo '<span class="breadcrumb-separator mx-2">' . esc_html( $separator ) . '</span>';			}		} elseif ( 'product' === get_post_type() && function_exists( 'wc_get_product_category_list' ) ) {			// If it's a product, show the product categories.			$product_categories = wc_get_product_category_list( get_the_ID() );			if ( $product_categories ) {				$product_categories = strip_tags( $product_categories );				$product_categories = explode( ', ', $product_categories );				$product_category = $product_categories[0];				echo '<span class="breadcrumb-item">' . wp_kses_post( $product_category ) . '</span>';				echo '<span class="breadcrumb-separator mx-2">' . esc_html( $separator ) . '</span>';			}		} elseif ( $post_type && 'page' !== get_post_type() ) {			// If it's a custom post type, show the post type archive link.			echo '<span class="breadcrumb-item"><a href="' . esc_url( get_post_type_archive_link( get_post_type() ) ) . '">' . esc_html( $post_type->labels->name ) . '</a></span>';			echo '<span class="breadcrumb-separator mx-2">' . esc_html( $separator ) . '</span>';		}		// Show the current post title.		echo '<span class="breadcrumb-item current">' . esc_html( get_the_title() ) . '</span>';	} elseif ( is_search() ) {		// Search results.		echo '<span class="breadcrumb-item current">' . esc_html__( 'Search results for', 'aqualuxe' ) . ' "' . esc_html( get_search_query() ) . '"</span>';	} elseif ( is_404() ) {		// 404 page.		echo '<span class="breadcrumb-item current">' . esc_html__( 'Page not found', 'aqualuxe' ) . '</span>';	}	echo '</div>';	echo '</div>';}/** * Display the pagination. */function aqualuxe_pagination() {	// Don't print empty markup if there's only one page.	if ( $GLOBALS['wp_query']->max_num_pages <= 1 ) {		return;	}	$paged        = get_query_var( 'paged' ) ? absint( get_query_var( 'paged' ) ) : 1;	$pagenum_link = html_entity_decode( get_pagenum_link() );	$query_args   = array();	$url_parts    = explode( '?', $pagenum_link );	if ( isset( $url_parts[1] ) ) {		wp_parse_str( $url_parts[1], $query_args );	}	$pagenum_link = remove_query_arg( array_keys( $query_args ), $pagenum_link );	$pagenum_link = trailingslashit( $pagenum_link ) . '%_%';	$format  = $GLOBALS['wp_rewrite']->using_index_permalinks() && ! strpos( $pagenum_link, 'index.php' ) ? 'index.php/' : '';	$format .= $GLOBALS['wp_rewrite']->using_permalinks() ? user_trailingslashit( 'page/%#%', 'paged' ) : '?paged=%#%';	// Set up paginated links.	$links = paginate_links(		array(			'base'      => $pagenum_link,			'format'    => $format,			'total'     => $GLOBALS['wp_query']->max_num_pages,			'current'   => $paged,			'mid_size'  => 1,			'add_args'  => array_map( 'urlencode', $query_args ),			'prev_text' => '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 19l-7-7 7-7"></path></svg>',			'next_text' => '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 5l7 7-7 7"></path></svg>',			'type'      => 'array',		)	);	if ( ! $links ) {		return;	}	echo '<nav class="pagination flex justify-center my-8" aria-label="' . esc_attr__( 'Posts navigation', 'aqualuxe' ) . '">';	echo '<ul class="flex space-x-2">';	foreach ( $links as $link ) {		$is_current = strpos( $link, 'current' ) !== false;		$classes    = 'flex items-center justify-center w-10 h-10 rounded-md border';		if ( $is_current ) {			$classes .= ' bg-primary-600 text-white border-primary-600';		} else {			$classes .= ' bg-white dark:bg-dark-700 text-dark-600 dark:text-light-500 border-gray-300 dark:border-dark-600 hover:bg-gray-100 dark:hover:bg-dark-600';		}		echo '<li class="pagination-item">';		echo str_replace( 'page-numbers', $classes, $link );		echo '</li>';	}	echo '</ul>';	echo '</nav>';}add_action( 'aqualuxe_pagination', 'aqualuxe_pagination' );/** * Display the post thumbnail with responsive image sizes. * * @param string $size The image size. */function aqualuxe_post_thumbnail( $size = 'post-thumbnail' ) {	if ( post_password_required() || is_attachment() || ! has_post_thumbnail() ) {		return;	}	if ( is_singular() ) :		?>		<div class="post-thumbnail mb-6">			<?php the_post_thumbnail( $size, array( 'class' => 'rounded-lg w-full h-auto' ) ); ?>		</div><!-- .post-thumbnail -->		<?php	else :		?>		<a class="post-thumbnail block mb-4" href="<?php the_permalink(); ?>" aria-hidden="true" tabindex="-1">			<?php			the_post_thumbnail(				$size,				array(					'class' => 'rounded-lg w-full h-auto',					'alt'   => the_title_attribute(						array(							'echo' => false,						)					),				)			);			?>		</a>		<?php	endif;}/** * Display the post meta. */function aqualuxe_post_meta() {	// Hide meta information for pages.	if ( 'post' !== get_post_type() ) {		return;	}	// Get the post meta settings.	$show_author = get_theme_mod( 'aqualuxe_show_post_author', true );	$show_date = get_theme_mod( 'aqualuxe_show_post_date', true );	$show_categories = get_theme_mod( 'aqualuxe_show_post_categories', true );	$show_tags = get_theme_mod( 'aqualuxe_show_post_tags', true );	$show_comments = get_theme_mod( 'aqualuxe_show_post_comments', true );	echo '<div class="entry-meta flex flex-wrap items-center text-sm text-gray-600 dark:text-gray-400 mb-4">';	// Author.	if ( $show_author ) {		echo '<span class="byline mr-4 mb-2">';		echo '<svg class="w-4 h-4 inline-block mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>';		echo '<span class="author vcard"><a class="url fn n hover:text-primary-600" href="' . esc_url( get_author_posts_url( get_the_author_meta( 'ID' ) ) ) . '">' . esc_html( get_the_author() ) . '</a></span>';		echo '</span>';	}	// Date.	if ( $show_date ) {		echo '<span class="posted-on mr-4 mb-2">';		echo '<svg class="w-4 h-4 inline-block mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>';		echo '<a class="hover:text-primary-600" href="' . esc_url( get_permalink() ) . '" rel="bookmark">' . esc_html( get_the_date() ) . '</a>';		echo '</span>';	}	// Categories.	if ( $show_categories && has_category() ) {		echo '<span class="cat-links mr-4 mb-2">';		echo '<svg class="w-4 h-4 inline-block mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z"></path></svg>';		echo get_the_category_list( ', ' );		echo '</span>';	}	// Tags.	if ( $show_tags && has_tag() ) {		echo '<span class="tags-links mr-4 mb-2">';		echo '<svg class="w-4 h-4 inline-block mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M7 20l4-16m2 16l4-16M6 9h14M4 15h14"></path></svg>';		echo get_the_tag_list( '', ', ' );		echo '</span>';	}	// Comments.	if ( $show_comments && ! post_password_required() && ( comments_open() || get_comments_number() ) ) {		echo '<span class="comments-link mb-2">';		echo '<svg class="w-4 h-4 inline-block mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"></path></svg>';		comments_popup_link(			sprintf(				wp_kses(					/* translators: %s: post title */					__( 'Leave a Comment<span class="screen-reader-text"> on %s</span>', 'aqualuxe' ),					array(						'span' => array(							'class' => array(),						),					)				),				get_the_title()			)		);		echo '</span>';	}	echo '</div><!-- .entry-meta -->';}